import{_ as a,o,c as t,ag as i}from"./chunks/framework.BZohXCq9.js";const r="/hofPlot.png",f=JSON.parse('{"title":"🏆 Hardcore Hall of Fame 🏆","description":"","frontmatter":{"outline":false},"headers":[],"relativePath":"pages/hof-info.md","filePath":"pages/hof-info.md","lastUpdated":1773600249000}'),l={name:"pages/hof-info.md"};function s(d,e,n,h,c,m){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="🏆-hardcore-hall-of-fame-🏆" tabindex="-1">🏆 Hardcore Hall of Fame 🏆 <a class="header-anchor" href="#🏆-hardcore-hall-of-fame-🏆" aria-label="Permalink to &quot;🏆 Hardcore Hall of Fame 🏆&quot;">​</a></h1><h4 id="a-minecraft-build-dedicated-to-my-top-supporters-in-the-twitch-community" tabindex="-1">A Minecraft build dedicated to my top supporters in the Twitch community <a class="header-anchor" href="#a-minecraft-build-dedicated-to-my-top-supporters-in-the-twitch-community" aria-label="Permalink to &quot;A Minecraft build dedicated to my top supporters in the Twitch community&quot;">​</a></h4><hr><p><strong>The Hall of Fame is a build in CoolAid&#39;s Hardcore world dedicated to his top supporters who have been most active members of the community. You need 3 or more days of watchtime on Twitch AND 25 Daily Totem redemptions to apply for a Hall of Fame plot.</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="'+r+'" alt="plot" width="800"></th></tr></thead><tbody><tr><td style="text-align:center;">Example HOF Plot (Fletcher199224)</td></tr></tbody></table><h1 id="hall-of-fame-faq" tabindex="-1">Hall of Fame FAQ <a class="header-anchor" href="#hall-of-fame-faq" aria-label="Permalink to &quot;Hall of Fame FAQ&quot;">​</a></h1><h3 id="q-how-can-i-apply-for-the-hof-once-i-am-eligible❓" tabindex="-1">Q. How can I apply for the HOF once I am eligible❓ <a class="header-anchor" href="#q-how-can-i-apply-for-the-hof-once-i-am-eligible❓" aria-label="Permalink to &quot;Q. How can I apply for the HOF once I am eligible❓&quot;">​</a></h3><p>For the application Google form <a href="https://docs.google.com/forms/d/e/1FAIpQLSdO8tFqPqHWK9bx5z2iTWX2G8-tafWylViIJnnAZE4twjISQw/viewform" target="_blank" rel="noreferrer">click here</a>, responses will be validated before accepted. Please join the hof-discussion channel in the Discord if you have any questions!</p><h3 id="q-how-do-i-add-items-to-my-plot❓" tabindex="-1">Q. How do I add items to my plot❓ <a class="header-anchor" href="#q-how-do-i-add-items-to-my-plot❓" aria-label="Permalink to &quot;Q. How do I add items to my plot❓&quot;">​</a></h3><p>All available blocks and items can be redeemed with Twitch channel points, which are earned just by watching the streams. Some blocks and items cost more than others. You can <a href="https://docs.google.com/spreadsheets/d/145x9910pUwjP6y4u008SjjX_q6jKdTfD7xz55zppjpg/edit?gid=0#gid=0" target="_blank" rel="noreferrer">click here</a> for the spreadsheet of every single available item!</p><h3 id="q-how-is-my-hof-plot-laid-out❓" tabindex="-1">Q. How is my HOF plot laid out❓ <a class="header-anchor" href="#q-how-is-my-hof-plot-laid-out❓" aria-label="Permalink to &quot;Q. How is my HOF plot laid out❓&quot;">​</a></h3><p><strong>All plots are given the same basic layout:</strong></p><ul><li>15 item frames to display items</li><li>Shelves to put microblocks on</li><li>Room for pets and more microblocks</li><li>Armor Stand to display armor and hold items or heads</li><li>Wall space for custom paintings, banners, or extra microblocks</li><li>A &quot;display case&quot; cubby for special redemptions (check the spreadsheet)</li><li>Free barrel under your Armor Stand to store extra items</li></ul><p><strong>(See the item spreadsheet and Twitch redemptions for specifics)</strong></p><h3 id="q-what-if-i-run-out-of-space-to-display-my-items❓" tabindex="-1">Q. What if I run out of space to display my items❓ <a class="header-anchor" href="#q-what-if-i-run-out-of-space-to-display-my-items❓" aria-label="Permalink to &quot;Q. What if I run out of space to display my items❓&quot;">​</a></h3><p>Every plot has a free barrel under their armor stand to store extra items, but can also redeem extra barrels for even more storage if you need as well! If you still somehow run out of space and fill up your whole plot, maybe go touch some grass.</p>',16)])])}const u=a(l,[["render",s]]);export{f as __pageData,u as default};
